<template><div class="toolbar"><el-input v-model="q" placeholder="查询日志"/><el-button @click="load">查询</el-button><el-button type="success" @click="csv">导出 CSV</el-button></div><el-table :data="rows" border><el-table-column prop="username" label="用户名"/><el-table-column prop="action" label="操作信息"/><el-table-column prop="time" label="操作时间"/><el-table-column prop="status" label="审计状态"/><el-table-column prop="integrity" label="HMAC完整性"/><el-table-column label="操作"><template #default="s"><el-button @click="audit(s.row.id)">审计</el-button><el-button type="danger" @click="del(s.row.id)">删除</el-button></template></el-table-column></el-table></template>
<script setup>import{ref,onMounted}from'vue';import{api}from'../api/http';const rows=ref([]),q=ref('');async function load(){rows.value=(await api.get('/logs',{params:{q:q.value}})).data}async function audit(id){await api.patch('/logs/'+id+'/audit');load()}async function del(id){await api.delete('/logs/'+id);load()}function csv(){const head='用户名,操作信息,操作时间,审计状态,HMAC完整性\n';const body=rows.value.map(r=>[r.username,r.action,r.time,r.status,r.integrity].map(x=>`"${String(x).replaceAll('"','""')}"`).join(',')).join('\n');const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([head+body],{type:'text/csv;charset=utf-8'}));a.download='日志审计.csv';a.click()}onMounted(load)</script>
